import React from "react"

const BemVindo = (props) => {
  return (    
    <div>
      <h2>Bem vindo(a) {props.nome}</h2>
      <h3>Tenho {props.anos}</h3>
    </div>    
  );
}

function App() {
  return (
    <div>
      <BemVindo nome="Lucas" anos="20"></BemVindo>
      <BemVindo nome="Amanda" anos="22"></BemVindo>
    </div>
  )
}

export default App;
